struct Stock {
    let symbol: String
    var price: Double
}

class Portfolio {
    var stocks: [Stock] = []
    
    func buyStock(symbol: String, price: Double, quantity: Int) {
        let newStock = Stock(symbol: symbol, price: price)
        for _ in 0..<quantity {
            stocks.append(newStock)
        }
    }
    
    func sellStock(symbol: String, price: Double, quantity: Int) {
        var remainingQuantity = quantity
        stocks = stocks.filter { stock in
            if stock.symbol == symbol && remainingQuantity > 0 {
                remainingQuantity -= 1
                return false
            }
            return true
        }
    }
}

